const body = $input.first().json.body;

const modo = body.modo || 'codigo'; // 'codigo' ou 'perguntas'

let userMessage = '';

if (modo === 'codigo') {
  userMessage = `Documenta o seguinte projeto/prompt/fluxo de automação:\n\n${body.conteudo}`;
} else {
  // modo perguntas
  userMessage = `Documenta um projeto com base nas seguintes informações:\n
- Nome do projeto: ${body.nome || 'Não informado'}
- O que faz: ${body.o_que_faz || 'Não informado'}
- Problema que resolve: ${body.problema || 'Não informado'}
- Ferramentas usadas: ${body.ferramentas || 'Não informado'}
- Resultado/impacto: ${body.resultado || 'Não informado'}
- Observações extras: ${body.observacoes || 'Nenhuma'}`;
}

return [{ json: { userMessage, modo, nome: body.nome || 'projeto' } }];

const response = $input.first().json;
const markdown = response.content[0].text;

// Gera nome do arquivo baseado na data e nome do projeto
const nome = $('Preparar Input').first().json.nome
  .toLowerCase()
  .replace(/\s+/g, '_')
  .replace(/[^a-z0-9_]/g, '');

const data = new Date().toISOString().slice(0, 10);
const filename = `${data}_${nome}.md`;

return [{ json: { markdown, filename } }];
